                public static void factorial(Integer n, Continuation<Integer> __continuation) {
    if ((n <= 1)) {
        __continuation.accept(1);
        return;
    } else {
        factorial((n - 1), (arg0) -> {
            __continuation.accept((n * arg0));
            return;
        });
    }
}
